import numpy as np

def tile_coding_hash(state: list, num_tilings: int, tiles_per_dim: int, memory_size: int, state_bounds: list = None) -> list:
    if state_bounds is None:
        state_bounds = [(0.0, 1.0)] * len(state)

    def djb2_hash(coords):
        h = 5381
        for c in coords:
            h = ((h * 33) + c) & 0xFFFFFFFF
        return h % memory_size

    active_tiles = []
    for t in range(num_tilings):
        offset = t / num_tilings
        coords = [t]
        for i, s in enumerate(state):
            low, high = state_bounds[i]
            normalized = (s - low) / (high - low) * tiles_per_dim
            shifted = normalized + offset
            coords.append(int(np.floor(shifted)))
        active_tiles.append(djb2_hash(coords))

    return active_tiles
